[ApiController]
public class UserController : ControllerBase
{
    [HttpPost]
    public IActionResult CreateUser(UserModel user) // Compliant: Validates ModelState
    {
        if (!ModelState.IsValid)
        {
            return BadRequest(ModelState);
        }

        SaveUser(user);
        return Ok();
    }

    [HttpPut]
    public IActionResult UpdateUser(UserModel user) // Compliant
    {
        if (!ModelState.IsValid)
        {
            return BadRequest(ModelState);
        }

        UpdateUserInDatabase(user);
        return Ok();
    }
}
